-        var ec: u32 = arr_index + 1;
-        while (true) {
-            const ew = p.tape.get(ec);
-            if (ew.tag == .array_closing) break;
-            if (ew.tag == .object_opening) {
-                var fc: u32 = ec + 1;
-                var fi: u32 = 0;
-                while (fi < field_idx) : (fi += 1) {
-                    const kw = p.tape.get(fc);
-                    if (kw.tag == .object_closing) break;
-                    const vw = p.tape.get(fc + 1);
-                    fc = switch (vw.tag) {
