-    fn addNode(self: *ValidatorState, node: SchemaNode) u16 {
-        if (self.node_count >= MAX_NODES) return 0xFFFF;
-        self.nodes[self.node_count] = node;
-        const idx = self.node_count;
-        self.node_count += 1;
