-                self.checkConst(node, tag, .{ .ptr = @ptrFromInt(1), .len = 0 }, 0);
-            },
-            .true_val, .false_val => {
-                _ = dr.readTag();
-                self.checkEnum(node, tag, .{ .ptr = @ptrFromInt(1), .len = 0 }, 0);
-                self.checkConst(node, tag, .{ .ptr = @ptrFromInt(1), .len = 0 }, 0);
-            },
-            .number => {
-                _ = dr.readTag();
