-        if (needed > self.cur_path_cap) return;
-        path[self.cur_path_len] = '.';
-        @memcpy(path[self.cur_path_len + 1 ..][0..key_len], key_ptr[0..key_len]);
-        self.cur_path_len = needed;
-    }
