+
+// ═══════════════════════════════════════════════════
+// Edge cases
+// ═══════════════════════════════════════════════════
+
+console.log("\n--- Edge cases ---");
+
+await test("isComplete: non-proxy object returns true", () => {
+  const r = vj.parse('{"a":1}');
